const items = $input.all();
const bills = items.map(i => i.json);
const count = bills.length;
if (count === 0) return [{ json: { count: 0, subject: '', htmlBody: '' } }];
const urgentCount = bills.filter(b => b.urgency === 'URGENT').length;
const totalAmount = bills.reduce((s, b) => s + parseFloat(b.amountDue || 0), 0);
const rows = bills.map(b => {
  const bg = b.urgency === 'URGENT' ? '#fff5f5' : 'white';
  const uc = b.urgency === 'URGENT' ? '#dc2626' : b.urgency === 'SOON' ? '#d97706' : '#16a34a';
  const days = b.daysLeft <= 0 ? (Math.abs(b.daysLeft) + 'd overdue') : (b.daysLeft + 'd left');
  const sup = (b.supplier && b.supplier.companyName) ? b.supplier.companyName : '-';
  return `<tr style='background:${bg}'><td style='padding:8px;border-bottom:1px solid #eee'>${b.billNumber}</td><td style='padding:8px;border-bottom:1px solid #eee'>${sup}</td><td style='padding:8px;border-bottom:1px solid #eee'>$${parseFloat(b.amountDue).toFixed(2)}</td><td style='padding:8px;border-bottom:1px solid #eee'>${b.dueDate}</td><td style='padding:8px;border-bottom:1px solid #eee'>${days}</td><td style='padding:8px;border-bottom:1px solid #eee;color:${uc}'>${b.urgency}</td></tr>`;
}).join('');
const urgentNote = urgentCount > 0 ? ` (${urgentCount} URGENT)` : '';
const htmlBody = `<h2 style='color:#1e3a5f'>AP Payment Reminders</h2><p>You have <strong>${count}</strong> payment(s) due this week — total <strong>$${totalAmount.toFixed(2)}</strong>${urgentNote}.</p><table style='border-collapse:collapse;width:100%;font-family:Arial,sans-serif;font-size:13px'><thead><tr style='background:#1e3a5f;color:white'><th style='padding:8px;text-align:left'>Bill #</th><th style='padding:8px;text-align:left'>Supplier</th><th style='padding:8px;text-align:left'>Amount</th><th style='padding:8px;text-align:left'>Due Date</th><th style='padding:8px;text-align:left'>Days Left</th><th style='padding:8px;text-align:left'>Urgency</th></tr></thead><tbody>${rows}</tbody></table><p style='color:#666;font-size:12px;margin-top:16px'>TSH Accounts Payable System — Auto-generated</p>`;
const subject = `[TSH AP] ${count} Payment${count > 1 ? 's' : ''} Due This Week${urgentCount > 0 ? ` — ${urgentCount} URGENT` : ''}`;
return [{ json: { count, subject, htmlBody } }];
